External Knowledge:
- 'building blocks' refers to exons, which are the regions of a gene that code for a part of a protein; 
- 'most central blueprints' refers to canonical transcripts, which are the most representative transcripts for each gene.

sql:
SELECT file_path, file_size
FROM genomic_data_files
WHERE file_size < 1024;

SELECT COUNT(*) AS number_of_files
FROM genomic_data_files
WHERE file_format = 'VCF';

SELECT reg_element_type, COUNT(*) AS element_count
FROM regulatory_elements
GROUP BY reg_element_type;

SELECT variation_type
FROM chromosomal_variations
WHERE variation_id = 1;

SELECT COUNT(*) 
FROM chromosomal_variations 
WHERE chrom_id = 1;

SELECT COUNT(gd.data_id) AS total_genomic_data_records
FROM genomic_data gd
JOIN (
  SELECT DISTINCT gene_id
  FROM access_logs
) al ON gd.gene_id = al.gene_id;

SELECT reg_element_description
FROM regulatory_elements
WHERE reg_element_type = 'enhancer';

SELECT COUNT(*) AS promoter_count
FROM regulatory_elements
WHERE reg_element_type = 'promoter';

SELECT region_type, COUNT(*) AS region_count
FROM genomic_regions
GROUP BY region_type;
